'use strict';
function aggregateSignals(signals) {
  return signals.reduce((acc, s) => { acc[s.name] = (acc[s.name] || 0) + s.value; return acc; }, {});
}
module.exports = { aggregateSignals };

'use strict';
function detectThreshold(values, threshold) {
  return values.filter(v => v > threshold).map((v, i) => ({ index: i, value: v, exceeded: v - threshold }));
}
module.exports = { detectThreshold };

'use strict';
function monitorConvergence(history) {
  if (history.length < 2) return { converged: false, reason: 'insufficient data' };
  const last = history[history.length - 1];
  const prev = history[history.length - 2];
  return { converged: last === prev, delta: last - prev };
}
module.exports = { monitorConvergence };

'use strict';
function calculateDrift(baseline, current) {
  const keys = Object.keys(baseline);
  let totalDrift = 0;
  for (const k of keys) { totalDrift += Math.abs((current[k] || 0) - baseline[k]); }
  return { totalDrift, avgDrift: keys.length ? totalDrift / keys.length : 0 };
}
module.exports = { calculateDrift };

'use strict';
function detectOscillation(values, windowSize) {
  const w = windowSize || 4;
  if (values.length < w * 2) return { oscillating: false };
  const recent = values.slice(-w);
  const prev = values.slice(-w * 2, -w);
  const avgRecent = recent.reduce((a, b) => a + b, 0) / w;
  const avgPrev = prev.reduce((a, b) => a + b, 0) / w;
  return { oscillating: Math.abs(avgRecent - avgPrev) < 0.01, amplitude: Math.abs(avgRecent - avgPrev) };
}
module.exports = { detectOscillation };

'use strict';
function scoreStability(residuals) {
  if (residuals.length < 2) return { score: 0, stable: false };
  let changes = 0;
  for (let i = 1; i < residuals.length; i++) { if (residuals[i] !== residuals[i-1]) changes++; }
  return { score: 1 - changes / (residuals.length - 1), stable: changes === 0 };
}
module.exports = { scoreStability };

'use strict';
function analyzeWaves(waves) {
  return { total: waves.length, avgLayers: waves.reduce((s, w) => s + w.layers.length, 0) / (waves.length || 1), maxLayers: Math.max(...waves.map(w => w.layers.length)) };
}
module.exports = { analyzeWaves };

'use strict';
function forecastResidual(history, steps) {
  if (history.length < 2) return { forecast: history[0] || 0, trend: 0 };
  const trend = (history[history.length-1] - history[0]) / history.length;
  return { forecast: Math.max(0, history[history.length-1] + trend * (steps || 1)), trend };
}
module.exports = { forecastResidual };
